import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { tasksAPI } from '../services/api';
import api from '../services/api';

export const TaskForm = ({ onSuccess, onCancel }) => {
  const { user } = useAuth();
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    department: user?.departments?.[0] || 'Production',
    assignedTo: '',
    deadline: '',
    priority: 'medium',
    extraFields: {},
  });

  const departments = ['CRM', 'Production', 'Sales', 'Service'];

  // Fetch employees on mount
  useEffect(() => {
    const fetchEmployees = async () => {
      try {
        const response = await api.get('/tasks', { params: { limit: 1000 } });
        // Get unique employees from tasks
        const uniqueEmployees = new Map();
        // Fetch from a dedicated endpoint if available, for now we'll use a simple list
        setEmployees([
          { id: 'emp1', name: 'emp1' },
          { id: 'emp2', name: 'emp2' },
          { id: 'emp3', name: 'emp3' },
        ]);
      } catch (err) {
        console.log('Could not fetch employees');
      }
    };

    fetchEmployees();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleExtraFieldChange = (key, value) => {
    setFormData(prev => ({
      ...prev,
      extraFields: {
        ...prev.extraFields,
        [key]: value,
      },
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (!formData.title || !formData.assignedTo || !formData.deadline) {
        setError('Please fill in all required fields');
        setLoading(false);
        return;
      }

      await tasksAPI.createTask(formData);
      onSuccess();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create task');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-lg shadow p-6 border-2 border-blue-500">
      <h2 className="text-2xl font-bold text-gray-800 mb-6">Create New Task</h2>

      {error && (
        <div className="mb-4 p-3 bg-red-100 border border-red-400 text-red-700 rounded">
          {error}
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
          {/* Title */}
          <div className="md:col-span-2">
            <label className="block text-gray-700 font-semibold mb-2">Task Title *</label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Enter task title"
            />
          </div>

          {/* Description */}
          <div className="md:col-span-2">
            <label className="block text-gray-700 font-semibold mb-2">Description</label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              rows="3"
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Enter task description"
            />
          </div>

          {/* Department */}
          <div>
            <label className="block text-gray-700 font-semibold mb-2">Department *</label>
            <select
              name="department"
              value={formData.department}
              onChange={handleChange}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {user?.departments?.map(dept => (
                <option key={dept} value={dept}>{dept}</option>
              ))}
            </select>
          </div>

          {/* Assigned To */}
          <div>
            <label className="block text-gray-700 font-semibold mb-2">Assign To *</label>
            <select
              name="assignedTo"
              value={formData.assignedTo}
              onChange={handleChange}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="">Select Employee</option>
              {employees.map(emp => (
                <option key={emp.id} value={emp.id}>{emp.name}</option>
              ))}
            </select>
          </div>

          {/* Deadline */}
          <div>
            <label className="block text-gray-700 font-semibold mb-2">Deadline *</label>
            <input
              type="datetime-local"
              name="deadline"
              value={formData.deadline}
              onChange={handleChange}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>

          {/* Priority */}
          <div>
            <label className="block text-gray-700 font-semibold mb-2">Priority</label>
            <select
              name="priority"
              value={formData.priority}
              onChange={handleChange}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </select>
          </div>
        </div>

        {/* Extra Fields */}
        <div className="mb-4 p-4 bg-gray-50 rounded">
          <label className="block text-gray-700 font-semibold mb-3">Additional Fields (Optional)</label>
          <div className="space-y-2 text-sm">
            <div>
              <label className="text-gray-600">Machine ID</label>
              <input
                type="text"
                value={formData.extraFields.machine || ''}
                onChange={(e) => handleExtraFieldChange('machine', e.target.value)}
                className="w-full px-3 py-1 border border-gray-300 rounded"
                placeholder="e.g., M1, M2"
              />
            </div>
            <div>
              <label className="text-gray-600">Shift</label>
              <input
                type="text"
                value={formData.extraFields.shift || ''}
                onChange={(e) => handleExtraFieldChange('shift', e.target.value)}
                className="w-full px-3 py-1 border border-gray-300 rounded"
                placeholder="e.g., morning, evening"
              />
            </div>
            <div>
              <label className="text-gray-600">Client/Other Info</label>
              <input
                type="text"
                value={formData.extraFields.clientName || ''}
                onChange={(e) => handleExtraFieldChange('clientName', e.target.value)}
                className="w-full px-3 py-1 border border-gray-300 rounded"
                placeholder="e.g., Client Name"
              />
            </div>
          </div>
        </div>

        {/* Buttons */}
        <div className="flex gap-3 justify-end">
          <button
            type="button"
            onClick={onCancel}
            className="px-6 py-2 bg-gray-500 text-white rounded-lg hover:bg-gray-600"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
          >
            {loading ? 'Creating...' : 'Create Task'}
          </button>
        </div>
      </form>
    </div>
  );
};
